import styled from 'styled-components';
 
 export const Page = styled.div`
  min-height: 100vh;
  min-width: 100vw;
  /* display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center; */
  background-color: peachpuff;
  opacity: 0.6;
`;

export const Corridor = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 60vh;
  min-width: 40vw;
  z-index: 2;
  background-image: url("/img/corridor.jpg")
`
